type SchemaDefinition = {
  [key: string]: 'string' | 'number' | 'boolean';
};

export class SchemaValidator<S extends SchemaDefinition> {
  private schema: S;

  constructor(schema: S) {
    this.schema = schema;
  }

  validate(data: any): { success: boolean; errors: string[] } {
    const errors: string[] = [];
    if (!data || typeof data !== 'object') {
      return { success: false, errors: ['Input data must be an object'] };
    }

    for (const key of Object.keys(this.schema)) {
      const expectedType = this.schema[key];
      const actualValue = data[key];

      if (actualValue === undefined) {
        errors.push(`Property "${key}" is missing`);
      } else if (typeof actualValue !== expectedType) {
        errors.push(`Property "${key}" must be of type "${expectedType}", got "${typeof actualValue}"`);
      }
    }

    return {
      success: errors.length === 0,
      errors
    };
  }
}
